'use strict';

/**
 * scope-diagrams.js  v6
 *
 * The key architectural change from v5:
 * Each illustration is first rendered as a standalone 180×180 PNG (via sharp),
 * then embedded as a base64 data URI <image> tag inside the card SVG.
 * This means librsvg renders a real rasterised image — NOT SVG path geometry —
 * so the output looks like actual rendered illustrations, not flat icons.
 *
 * Diagram 1: System Context Diagram — RADIAL layout
 * Diagram 2: Scope Boundary Diagram — card-grid layout (unchanged)
 *
 * Dependencies: sharp (SVG→PNG). No browser required.
 */

const { svgToPng, wrapText, esc } = require('./svg-utils');

const FONT = 'Arial,Helvetica,sans-serif';

const C = {
  cardColors: [
    ['#1abc9c', '#16a085'],
    ['#2980b9', '#1a5276'],
    ['#27ae60', '#1e8449'],
    ['#e67e22', '#d35400'],
    ['#f39c12', '#d68910'],
    ['#8e44ad', '#6c3483'],
    ['#c0392b', '#96281b'],
    ['#16a085', '#0e6655']
  ],
  navyGrad: ['#1F3864', '#2E5496'],
  navy: '#1F3864',
  navyLight: '#2E5496',
  green: '#27ae60',
  greenPale: '#eafaf1',
  red: '#c0392b',
  redPale: '#fdedec',
  light: '#f0f4f8',
  textDark: '#1a252f',
  arrow: '#5b9bd5',
  shadow: 'rgba(0,0,0,0.22)'
};

const ILL_SIZE = 180; // each illustration is 180×180px

// Pre-rendered illustration PNGs as base64 — 27 distinct types
const ILLO_B64 = {
  govt: '',
  server:
    '',
  shield:
    '',
  legal:
    '',
  financial:
    '',
  env: '',
  advisory:
    '',
  engineering:
    '',
  director:
    '',
  procurement:
    '',
  partnership:
    '',
  committee:
    '',
  investor:
    '',
  manager:
    '',
  regulatory:
    '',
  bank: '',
  telecom:
    '',
  health:
    '',
  software:
    '',
  education:
    '',
  community:
    '',
  infrastructure:
    '',
  audit:
    '',
  media:
    '',
  transport:
    '',
  security:
    '',
  energy:
    ''
};

function _has(text, word) {
  // Word-boundary safe match: word must not be mid-word
  const i = text.indexOf(word);
  if (i === -1) return false;
  const before = i > 0 ? text[i - 1] : ' ';
  const after = i + word.length < text.length ? text[i + word.length] : ' ';
  return !/[a-z0-9]/.test(before) && !/[a-z0-9]/.test(after);
}

function selectIlloName(name, role, isSystem) {
  if (isSystem) return 'server';
  const n = (name || '').toLowerCase();
  const r = (role || '').toLowerCase();
  const t = n + ' ' + r;

  // ENVIRONMENT
  if (t.includes('environment') || t.includes(' epa') || t.includes('ecology') || t.includes('climate') || t.includes('pollution')) return 'env';

  // LEGAL
  if (t.includes('legal') || t.includes('jd/') || t.includes('llm') || t.includes('bar at law') || t.includes('solicitor') || t.includes('attorney') || t.includes('counsel')) return 'legal';

  // SECURITY / CYBER
  if (t.includes('cyber') || t.includes('information security') || t.includes('ciso') || t.includes('data protection')) return 'security';

  // AUDIT / COMPLIANCE (name only for 'compliance' to avoid false matches in role)
  if (n.includes('audit') || n.includes('compliance') || n.includes('inspector') || n.includes('controller') || n.includes('examiner')) return 'audit';

  // PROCUREMENT (name-specific to avoid 'procurement' in role text polluting other types)
  if (n.includes('procurement') || n.includes('ppra') || n.includes('purchasing') || n.includes('tendering')) return 'procurement';
  if (t.includes('qcbs') || t.includes('procurement regulator') || t.includes('procurement methodology')) return 'procurement';

  // PPP / PARTNERSHIP AUTHORITY
  if (n.includes('ppp') || n.includes('p3a') || t.includes('public private partnership') || t.includes('partnership authority')) return 'partnership';
  if (t.includes('statutory ppp') || t.includes('ppp regulator') || t.includes('ppp qualification')) return 'partnership';

  // COMMITTEE / BOARD / STEERING
  if (n.includes('committee') || n.includes('steering') || n.includes('council') || n.includes('panel') || n.includes('oversight body') || n.includes('governance body')) return 'committee';

  // PRIVATE INVESTOR / BIDDER
  if (
    n.includes('investor') ||
    n.includes('bidder') ||
    n.includes('concessionaire') ||
    n.includes('private sector') ||
    n.includes('private party') ||
    n.includes('prospective') ||
    n.includes('consortium')
  )
    return 'investor';

  // PROJECT MANAGER
  if (t.includes('project manager') || t.includes('project coordinator') || t.includes('site manager') || t.includes('construction manager') || t.includes('project officer')) return 'manager';

  // DIRECTOR / EXECUTIVE
  if (n.includes('director') || n.includes('president') || t.includes('head of') || t.includes('vice president')) return 'director';
  if (n.includes('chief') || n.includes(' ceo') || n.includes(' cto') || n.includes(' cfo')) return 'director';

  // TELECOM
  if (t.includes('telecom') || t.includes('telecommunication') || t.includes('network operator') || t.includes('broadband') || t.includes('ict operator')) return 'telecom';

  // SOFTWARE / IT
  if (t.includes('software') || t.includes('it department') || t.includes('information technology') || t.includes('technology partner') || t.includes('systems integrat') || t.includes('developer'))
    return 'software';

  // HEALTHCARE
  if (t.includes('hospital') || t.includes('clinic') || t.includes('pharma') || t.includes('patient')) return 'health';
  if (t.includes('health') && !t.includes('public health policy')) return 'health';

  // EDUCATION
  if (t.includes('educat') || t.includes('university') || t.includes('academic') || t.includes('research institute') || t.includes('he commission') || t.includes(' school')) return 'education';

  // TRANSPORT - use _has() for short 'port' to prevent matching 'support','report'
  if (t.includes('transport') || t.includes('logistics') || t.includes('railway') || t.includes('aviation') || t.includes('highway') || t.includes('road network') || t.includes('road authority'))
    return 'transport';
  if (_has(t, 'port') || t.includes(' nha') || t.includes('nhmp')) return 'transport';

  // INFRASTRUCTURE / UTILITIES
  if (t.includes('infrastructure') || t.includes('utilities') || t.includes('sewage') || t.includes('municipal') || t.includes('civic works')) return 'infrastructure';
  if (t.includes('water supply') || t.includes('water utility') || t.includes('water authority')) return 'infrastructure';

  // ENERGY
  if (
    t.includes('energy') ||
    t.includes('electricity') ||
    t.includes('renewable') ||
    t.includes('solar') ||
    t.includes('wapda') ||
    t.includes('nepra') ||
    t.includes('power generation') ||
    t.includes('power transmission')
  )
    return 'energy';

  // COMMUNITY / CITIZENS
  if (t.includes('community') || t.includes('citizen') || t.includes('resident') || t.includes('beneficiar') || t.includes('end user') || t.includes('general public')) return 'community';

  // MEDIA / COMMUNICATIONS
  if (t.includes('media') || t.includes('broadcast') || t.includes(' press') || t.includes('pmra') || t.includes('public relation')) return 'media';
  if (t.includes('communication') && !t.includes('telecommunication')) return 'media';

  // BANK
  if (t.includes(' bank') || t.includes('sbp') || t.includes('central bank') || t.includes('microfinance') || t.includes('nbfi') || t.includes('secp')) return 'bank';

  // FINANCIAL (after bank to avoid overlap; use 'ministry of finance' explicitly)
  if (t.includes('ministry of finance') || t.includes('fiscal') || t.includes('treasury') || t.includes('ca/') || t.includes(' cfa') || t.includes('acca')) return 'financial';
  if (t.includes('finance') || t.includes('financial')) return 'financial';
  if (n.includes('budget') && !n.includes('budget airline')) return 'financial';

  // ENGINEERING / CONSTRUCTION
  if (t.includes('engineer') || t.includes('be/ms') || t.includes('structural') || t.includes('civil works')) return 'engineering';

  // ADVISORY / CONSULTANT / FIRM
  if (
    t.includes('advisor') ||
    t.includes('advisory') ||
    t.includes('consultant') ||
    t.includes('selected firm') ||
    t.includes('lead firm') ||
    t.includes('service provider') ||
    t.includes('contractor') ||
    t.includes('transaction advisor')
  )
    return 'advisory';

  // REGULATORY AUTHORITY
  if (n.includes('regulatory') || n.includes('regulator') || n.includes('commission') || n.includes('bureau')) return 'regulatory';
  if (n.includes('authority') && !n.includes('local authority')) return 'regulatory';
  if (n.includes('agency') && !n.includes('news agency')) return 'regulatory';

  // GOVERNMENT MINISTRY
  if (t.includes('ministry') || t.includes('mopd') || t.includes('federal') || t.includes('national') || t.includes('department of')) return 'govt';
  if (t.includes('government') && !t.includes('non-government')) return 'govt';

  // DEFAULT
  return 'shield';
}

// ─────────────────────────────────────────────────────────────────────────────
// DIAGRAM 1 — RADIAL SYSTEM CONTEXT
// ─────────────────────────────────────────────────────────────────────────────

async function buildSystemContextSvg({ projectName, stakeholders }) {
  const illoMap = ILLO_B64;

  const titleBarH = 48;
  const boxW = 165;
  const illoAreaH = 102;
  const nameFontSz = 10.5,
    roleFontSz = 9;
  const nameLineH = 13.5,
    roleLineH = 11.5;
  const nameMaxCh = 17,
    roleMaxCh = 20;
  const padT = 6,
    padB = 8;

  const actors = (stakeholders || []).slice(0, 8);
  const actorMeta = actors.map(actor => {
    const nameLines = wrapText(actor.name || 'Actor', nameMaxCh);
    const roleLines = wrapText(actor.role || '', roleMaxCh).slice(0, 3);
    const textH = nameLines.length * nameLineH + (roleLines[0] ? roleLines.length * roleLineH + 4 : 0);
    const boxH = illoAreaH + padT + textH + padB;
    return { actor, nameLines, roleLines, boxH };
  });

  const sysNameLines = wrapText(projectName || 'System', 18);
  const sysW = 175,
    sysH = 86;
  const maxBoxH = Math.max(...actorMeta.map(m => m.boxH), 130);
  const radius = Math.max(240, Math.sqrt(boxW * boxW + maxBoxH * maxBoxH) / 2 + sysW / 2 + 54);
  const n = actors.length;
  const positions = actors.map((_, i) => ({
    ax: radius * Math.cos(-Math.PI / 2 + (i * 2 * Math.PI) / n),
    ay: radius * Math.sin(-Math.PI / 2 + (i * 2 * Math.PI) / n)
  }));

  const allX = positions.map((p, i) => [p.ax - boxW / 2 - 12, p.ax + boxW / 2 + 12]).flat();
  const allY = positions.map((p, i) => [p.ay - actorMeta[i].boxH / 2 - 12, p.ay + actorMeta[i].boxH / 2 + 12]).flat();
  const minX = Math.min(...allX, -sysW / 2 - 14),
    maxX = Math.max(...allX, sysW / 2 + 14);
  const minY = Math.min(...allY, -sysH / 2 - 14),
    maxY = Math.max(...allY, sysH / 2 + 14);
  const offX = -minX + 24,
    offY = -minY + titleBarH + 24;
  const W = maxX - minX + 48,
    H = maxY - minY + titleBarH + 48;

  let defs = `
    <linearGradient id="tg" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="${C.navyGrad[0]}"/>
      <stop offset="100%" stop-color="${C.navyGrad[1]}"/>
    </linearGradient>
    <linearGradient id="sg" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${C.navyGrad[1]}"/>
      <stop offset="100%" stop-color="${C.navyGrad[0]}"/>
    </linearGradient>
    <marker id="arr" markerWidth="9" markerHeight="7" refX="8" refY="3.5" orient="auto">
      <polygon points="0 0,9 3.5,0 7" fill="${C.arrow}"/>
    </marker>
    <marker id="arrR" markerWidth="9" markerHeight="7" refX="1" refY="3.5" orient="auto">
      <polygon points="9 0,0 3.5,9 7" fill="${C.arrow}"/>
    </marker>`;

  actorMeta.forEach((meta, i) => {
    const [c1, c2] = C.cardColors[i % C.cardColors.length];
    const { ax, ay } = positions[i];
    const bx = ax - boxW / 2 + offX,
      by = ay - meta.boxH / 2 + offY;
    defs += `
    <linearGradient id="cg${i}" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${c1}"/>
      <stop offset="100%" stop-color="${c2}"/>
    </linearGradient>
    <clipPath id="cp${i}"><rect x="${bx.toFixed(1)}" y="${by.toFixed(1)}" width="${boxW}" height="${meta.boxH.toFixed(1)}" rx="13"/></clipPath>`;
  });

  let arrows = '',
    cards = '';
  const sysCx = offX,
    sysCy = offY;

  actorMeta.forEach((meta, i) => {
    const { ax, ay } = positions[i];
    const bx = ax - boxW / 2 + offX,
      by = ay - meta.boxH / 2 + offY;
    const acx = ax + offX,
      acy = ay + offY;

    const dx = sysCx - acx,
      dy = sysCy - acy,
      len = Math.sqrt(dx * dx + dy * dy);
    const ux = dx / len,
      uy = dy / len;
    const tBox = Math.min(boxW / 2 / Math.abs(ux || 0.001), meta.boxH / 2 / Math.abs(uy || 0.001));
    const tSys = Math.min(sysW / 2 / Math.abs(ux || 0.001), sysH / 2 / Math.abs(uy || 0.001));
    arrows += `<line x1="${(acx + ux * (tBox + 2)).toFixed(1)}" y1="${(acy + uy * (tBox + 2)).toFixed(1)}" x2="${(sysCx - ux * (tSys + 2)).toFixed(1)}" y2="${(sysCy - uy * (tSys + 2)).toFixed(1)}" stroke="${C.arrow}" stroke-width="1.8" stroke-dasharray="7 4" marker-end="url(#arr)" marker-start="url(#arrR)"/>`;

    // Card
    cards += `<rect x="${(bx + 4).toFixed(1)}" y="${(by + 4).toFixed(1)}" width="${boxW}" height="${meta.boxH.toFixed(1)}" rx="13" fill="${C.shadow}"/>`;
    cards += `<rect x="${bx.toFixed(1)}" y="${by.toFixed(1)}" width="${boxW}" height="${meta.boxH.toFixed(1)}" rx="13" fill="url(#cg${i})"/>`;

    // Embedded illustration image (pre-rendered PNG as base64)
    const illoName = selectIlloName(meta.actor.name, meta.actor.role, false);
    const b64 = illoMap[illoName];
    if (b64) {
      const imgW = boxW - 16;
      const imgH = illoAreaH - 2;
      const imgX = bx + 8;
      const imgY = by + 4;
      cards += `<image href="data:image/png;base64,${b64}" x="${imgX.toFixed(1)}" y="${imgY.toFixed(1)}" width="${imgW}" height="${imgH}" clip-path="url(#cp${i})" preserveAspectRatio="xMidYMid meet"/>`;
    }

    // Text below illustration
    const tsy = by + illoAreaH + padT;
    meta.nameLines.forEach((line, li) => {
      cards += `<text x="${acx.toFixed(1)}" y="${(tsy + li * nameLineH + nameFontSz * 0.82).toFixed(1)}" font-family="${FONT}" font-size="${nameFontSz}" font-weight="700" text-anchor="middle" fill="white" clip-path="url(#cp${i})">${esc(line)}</text>`;
    });
    if (meta.roleLines[0]) {
      const rsy = tsy + meta.nameLines.length * nameLineH + 3;
      cards += `<line x1="${(bx + 14).toFixed(1)}" y1="${(rsy - 3).toFixed(1)}" x2="${(bx + boxW - 14).toFixed(1)}" y2="${(rsy - 3).toFixed(1)}" stroke="rgba(255,255,255,0.3)" stroke-width="0.8" clip-path="url(#cp${i})"/>`;
      meta.roleLines.forEach((line, li) => {
        cards += `<text x="${acx.toFixed(1)}" y="${(rsy + li * roleLineH + roleFontSz * 0.82).toFixed(1)}" font-family="${FONT}" font-size="${roleFontSz}" text-anchor="middle" fill="rgba(255,255,255,0.88)" clip-path="url(#cp${i})">${esc(line)}</text>`;
      });
    }
  });

  // Centre system node
  const sysX = sysCx - sysW / 2,
    sysY = sysCy - sysH / 2;
  cards += `<rect x="${(sysX + 4).toFixed(1)}" y="${(sysY + 4).toFixed(1)}" width="${sysW}" height="${sysH}" rx="16" fill="rgba(0,0,0,0.28)"/>`;
  cards += `<rect x="${sysX.toFixed(1)}" y="${sysY.toFixed(1)}" width="${sysW}" height="${sysH}" rx="16" fill="url(#sg)" stroke="rgba(255,255,255,0.2)" stroke-width="1.5"/>`;
  // Centre node: text only — no illustration to avoid overlap
  const stsy = sysCy - (sysNameLines.length * 15) / 2 + 6;
  sysNameLines.forEach((line, li) => {
    cards += `<text x="${sysCx.toFixed(1)}" y="${(stsy + li * 14).toFixed(1)}" font-family="${FONT}" font-size="11" font-weight="700" text-anchor="middle" fill="white">${esc(line)}</text>`;
  });

  const legendY = H - 16;
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
  <defs>${defs}</defs>
  <rect width="${W}" height="${H}" fill="${C.light}"/>
  <rect x="0" y="0" width="${W}" height="${titleBarH}" fill="url(#tg)"/>
  <text x="${(W / 2).toFixed(1)}" y="${(titleBarH - 14).toFixed(1)}" font-family="${FONT}" font-size="14" font-weight="700" fill="white" text-anchor="middle">System Context Diagram \u2014 ${esc(projectName || 'System')}</text>
  ${arrows}
  ${cards}
  <line x1="24" y1="${legendY}" x2="52" y2="${legendY}" stroke="${C.arrow}" stroke-width="1.8" stroke-dasharray="7 4" marker-end="url(#arr)" marker-start="url(#arrR)"/>
  <text x="58" y="${legendY + 4}" font-family="${FONT}" font-size="9" fill="${C.textDark}">Interaction</text>
</svg>`;
}

// ─────────────────────────────────────────────────────────────────────────────
// DIAGRAM 2 — SCOPE BOUNDARY (unchanged)
// ─────────────────────────────────────────────────────────────────────────────

function buildScopeBoundarySvg({ projectName, inScope, outOfScope }) {
  const titleBarH = 46,
    headerH = 46;
  const inItems = (inScope || []).slice(0, 16),
    outItems = (outOfScope || []).slice(0, 14);
  const inPerRow = 2,
    inCardH = 52,
    inCardGap = 5;
  const inRows = Math.ceil(Math.max(inItems.length, 1) / inPerRow);
  const outCardH = 48,
    outGap = 5;
  const bodyH = Math.max(inRows * (inCardH + inCardGap) + 8, outItems.length * (outCardH + outGap) + 8, 80);
  const W = 900,
    H = titleBarH + headerH + bodyH + 16,
    colW = W / 2,
    bodyY = titleBarH;
  const chk = (cx, cy, r, c) => {
    const d = r * 0.42;
    return `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${c}" opacity="0.16"/><path d="M${(cx - d).toFixed(1)},${(cy + d * 0.06).toFixed(1)} L${(cx - d * 0.1).toFixed(1)},${(cy + d * 0.9).toFixed(1)} L${(cx + d * 0.9).toFixed(1)},${(cy - d * 0.68).toFixed(1)}" fill="none" stroke="${c}" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/>`;
  };
  const crs = (cx, cy, r, c) => {
    const d = r * 0.44;
    return `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${c}" opacity="0.16"/><line x1="${(cx - d).toFixed(1)}" y1="${(cy - d).toFixed(1)}" x2="${(cx + d).toFixed(1)}" y2="${(cy + d).toFixed(1)}" stroke="${c}" stroke-width="2.2" stroke-linecap="round"/><line x1="${(cx + d).toFixed(1)}" y1="${(cy - d).toFixed(1)}" x2="${(cx - d).toFixed(1)}" y2="${(cy + d).toFixed(1)}" stroke="${c}" stroke-width="2.2" stroke-linecap="round"/>`;
  };
  let items = '';
  const inCardW = (colW - 18) / inPerRow;
  inItems.forEach((item, i) => {
    const col = i % inPerRow,
      row = Math.floor(i / inPerRow);
    const x = 4 + col * (inCardW + inCardGap),
      y = bodyY + headerH + 6 + row * (inCardH + inCardGap);
    const cx = x + 24,
      cy = y + inCardH / 2;
    const isObj = typeof item === 'object' && item !== null;
    const id = isObj ? item.id || '' : '',
      title = isObj ? item.title || '' : String(item || '');
    items += `<rect x="${(x + 4).toFixed(1)}" y="${(y + 2).toFixed(1)}" width="${(inCardW - 8).toFixed(1)}" height="${(inCardH - 4).toFixed(1)}" rx="8" fill="${C.green}" opacity="0.10"/>
  <rect x="${(x + 4).toFixed(1)}" y="${(y + 2).toFixed(1)}" width="${(inCardW - 8).toFixed(1)}" height="${(inCardH - 4).toFixed(1)}" rx="8" fill="none" stroke="${C.green}" stroke-width="1.2" opacity="0.38"/>
  ${chk(cx, cy, 13, C.green)}
  ${id ? `<text x="${(x + 44).toFixed(1)}" y="${(cy - 5).toFixed(1)}" font-family="${FONT}" font-size="8" font-weight="700" fill="${C.green}">${esc(id)}</text>` : ''}
  <text x="${(x + 44).toFixed(1)}" y="${(cy + (id ? 9 : 5)).toFixed(1)}" font-family="${FONT}" font-size="10" fill="${C.textDark}">${esc(title.length > 32 ? title.substring(0, 30) + '...' : title)}</text>`;
  });
  const outCardW = colW - 16;
  outItems.forEach((item, i) => {
    const x = colW + 6,
      y = bodyY + headerH + 6 + i * (outCardH + outGap);
    const cx = x + 24,
      cy = y + outCardH / 2;
    const txt = typeof item === 'string' ? item : item && item.title ? item.title : String(item);
    items += `<rect x="${(x + 4).toFixed(1)}" y="${(y + 2).toFixed(1)}" width="${(outCardW - 8).toFixed(1)}" height="${(outCardH - 4).toFixed(1)}" rx="8" fill="${C.red}" opacity="0.10"/>
  <rect x="${(x + 4).toFixed(1)}" y="${(y + 2).toFixed(1)}" width="${(outCardW - 8).toFixed(1)}" height="${(outCardH - 4).toFixed(1)}" rx="8" fill="none" stroke="${C.red}" stroke-width="1.2" opacity="0.38"/>
  ${crs(cx, cy, 13, C.red)}
  <text x="${(x + 44).toFixed(1)}" y="${(cy + 5).toFixed(1)}" font-family="${FONT}" font-size="10" fill="${C.textDark}">${esc(txt.length > 48 ? txt.substring(0, 46) + '...' : txt)}</text>`;
  });
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
  <defs><linearGradient id="sbTG" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="${C.navy}"/><stop offset="100%" stop-color="${C.navyLight}"/></linearGradient></defs>
  <rect width="${W}" height="${H}" fill="${C.light}"/>
  <rect x="0" y="0" width="${W}" height="${titleBarH}" fill="url(#sbTG)"/>
  <text x="${(W / 2).toFixed(1)}" y="${(titleBarH - 13).toFixed(1)}" font-family="${FONT}" font-size="14" font-weight="700" fill="white" text-anchor="middle">Scope Boundary \u2014 ${esc(projectName || 'Project')}</text>
  <rect x="0" y="${bodyY}" width="${colW}" height="${H - bodyY}" fill="${C.greenPale}"/>
  <rect x="${colW}" y="${bodyY}" width="${colW}" height="${H - bodyY}" fill="${C.redPale}"/>
  <rect x="0" y="${bodyY}" width="${colW}" height="${headerH}" fill="${C.green}"/>
  <text x="${(colW / 2).toFixed(1)}" y="${(bodyY + 30).toFixed(1)}" font-family="${FONT}" font-size="13" font-weight="700" fill="white" text-anchor="middle">IN SCOPE</text>
  <rect x="${colW}" y="${bodyY}" width="${colW}" height="${headerH}" fill="${C.red}"/>
  <text x="${(colW + colW / 2).toFixed(1)}" y="${(bodyY + 30).toFixed(1)}" font-family="${FONT}" font-size="13" font-weight="700" fill="white" text-anchor="middle">OUT OF SCOPE</text>
  ${items}
  <line x1="${colW}" y1="${bodyY}" x2="${colW}" y2="${H}" stroke="rgba(0,0,0,0.10)" stroke-width="1.5"/>
</svg>`;
}

// ─────────────────────────────────────────────────────────────────────────────
// ORCHESTRATOR
// ─────────────────────────────────────────────────────────────────────────────

async function buildScopeDiagrams(scopeRenderData) {
  const { projectName, inScope, outOfScopeBullets, stakeholders } = scopeRenderData;
  const outOfScope = Array.isArray(outOfScopeBullets) ? outOfScopeBullets.filter(s => s && s !== 'TBD') : [];
  const contextSvg = await buildSystemContextSvg({ projectName, stakeholders: stakeholders || [] });
  const [systemContextPng, scopeBoundaryPng] = await Promise.all([svgToPng(contextSvg), svgToPng(buildScopeBoundarySvg({ projectName, inScope: inScope || [], outOfScope }))]);
  return { systemContextPng, scopeBoundaryPng };
}

module.exports = { buildScopeDiagrams, buildSystemContextSvg, buildScopeBoundarySvg };
